export const notes = "<div class=\"notes-card\">\n  <h3>Section 1: The 5-Step Geographical Inquiry Process</h3>\n  <div class=\"process-flow\">\n    <div class=\"process-step\">\n      <span class=\"step-num\">1</span>\n      <div>\n        <strong>Pose a Geographical Question</strong>\n        <ul>\n          <li>Identify a topic or problem to investigate</li>\n          <li>Ask a clear, focused, measurable question</li>\n          <li>Examples: \"How does land use change with distance from the CBD?\" / \"How does vegetation change with altitude?\"</li>\n          <li>The question must be geographical \u2014 spatial, environmental, or related to human\u2013environment interaction</li>\n          <li>Must be testable with data you can collect</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"process-step\">\n      <span class=\"step-num\">2</span>\n      <div>\n        <strong>Collect Geographical Data</strong>\n        <ul>\n          <li>Plan data collection: What data? Where? When? How many samples?</li>\n          <li><strong>Primary data:</strong> Collected directly by the investigator (fieldwork)</li>\n          <li><strong>Secondary data:</strong> Collected by others (existing records, published sources)</li>\n          <li>Sampling strategies: Random, Systematic, Stratified</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"process-step\">\n      <span class=\"step-num\">3</span>\n      <div>\n        <strong>Analyse Geographical Data</strong>\n        <ul>\n          <li>Process and organise raw data</li>\n          <li>Calculate statistics (mean, median, mode, range, percentages)</li>\n          <li>Identify patterns, trends, and anomalies</li>\n          <li>Compare data across different locations or times</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"process-step\">\n      <span class=\"step-num\">4</span>\n      <div>\n        <strong>Draw Conclusions</strong>\n        <ul>\n          <li>Answer the original geographical question</li>\n          <li>Refer directly to data collected</li>\n          <li>Identify limitations of data or method</li>\n          <li>Compare to expected patterns or theories</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"process-step\">\n      <span class=\"step-num\">5</span>\n      <div>\n        <strong>Reflect on the Inquiry</strong>\n        <ul>\n          <li>Evaluate the quality and reliability of data</li>\n          <li>Suggest improvements to methods</li>\n          <li>Propose further questions for investigation</li>\n          <li>Consider sources of error or bias</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n  <div class=\"exam-tip\">The 5-step process is sometimes called the <strong>Geographical Enquiry Cycle</strong>. In exams, you may be asked to identify which step a given activity belongs to.</div>\n</div>\n\n<div class=\"notes-card\">\n  <h3>Section 2: Primary Data Collection Methods</h3>\n  <p>Primary data is collected <strong>first-hand</strong> by the investigator during fieldwork.</p>\n  <table style=\"width:100%;border-collapse:collapse;\">\n    <tr style=\"background:#e8f4f8;\"><th style=\"padding:6px;border:1px solid #ccc;\">Method</th><th style=\"padding:6px;border:1px solid #ccc;\">Description</th><th style=\"padding:6px;border:1px solid #ccc;\">Advantages</th><th style=\"padding:6px;border:1px solid #ccc;\">Disadvantages</th></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Field Sketches</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Hand-drawn sketch of a geographical scene (river, coastline, landscape); annotated with landforms, vegetation, land use, scale/direction</td><td style=\"padding:6px;border:1px solid #ccc;\">Quick; captures spatial relationships; original record</td><td style=\"padding:6px;border:1px solid #ccc;\">Subjective; requires drawing skill; no exact measurements</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Questionnaires / Interviews</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Structured (fixed questions) or semi-structured (some open questions); gathers opinions, behaviour, demographics</td><td style=\"padding:6px;border:1px solid #ccc;\">Direct information from people; covers attitudes and perceptions</td><td style=\"padding:6px;border:1px solid #ccc;\">Biased responses; people may not answer honestly; time-consuming</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Measurements</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Quantitative data: river velocity (float method), beach profile, temperature, noise levels; recorded in standard units</td><td style=\"padding:6px;border:1px solid #ccc;\">Objective; repeatable; comparable across sites</td><td style=\"padding:6px;border:1px solid #ccc;\">Equipment cost; operator error; snapshot in time only</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Observation / Recording</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Tally charts to count traffic, pedestrians, land uses, plant species; photography to document landscape</td><td style=\"padding:6px;border:1px solid #ccc;\">Direct evidence; photography creates visual record</td><td style=\"padding:6px;border:1px solid #ccc;\">Time-consuming; observer bias; landscape changes over time</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Sampling Strategies</strong></td><td style=\"padding:6px;border:1px solid #ccc;\"><em>Random:</em> equal chance for all; <em>Systematic:</em> regular intervals; <em>Stratified:</em> proportional from subgroups; <em>Quadrat:</em> random placement to count organisms</td><td style=\"padding:6px;border:1px solid #ccc;\">Reduces bias; manageable data size; representative if done correctly</td><td style=\"padding:6px;border:1px solid #ccc;\">Can still miss key areas; stratified requires prior knowledge of groups</td></tr>\n  </table>\n  <div class=\"exam-tip\">Know the difference between random, systematic, and stratified sampling \u2014 examiners often ask you to choose and justify the most suitable strategy for a given scenario.</div>\n</div>\n\n<div class=\"notes-card\">\n  <h3>Section 3: Secondary Data Sources</h3>\n  <p>Secondary data was <strong>collected by others</strong> before the investigation.</p>\n  <ul>\n    <li><strong>Newspapers and media reports:</strong> Useful for events, public opinions, trends \u2014 but may be biased or sensationalised</li>\n    <li><strong>Government statistics:</strong> Census data, population data, economic data (e.g., Singapore Department of Statistics) \u2014 reliable but may lag behind real time</li>\n    <li><strong>Maps (OS, land use, topographic):</strong> Show spatial patterns \u2014 may be outdated; projection can distort areas</li>\n    <li><strong>Satellite images:</strong> Show land use change, deforestation, urban growth (e.g., Google Earth) \u2014 powerful for large-scale change over time</li>\n    <li><strong>Academic publications and textbooks:</strong> Peer-reviewed, reliable \u2014 but complex and may not match exact location needed</li>\n    <li><strong>Organisation reports:</strong> WWF, UN, FAO reports on environment, water, deforestation \u2014 authoritative but may have organisational agenda</li>\n  </ul>\n  <div class=\"compare-grid\">\n    <div class=\"compare-col\">\n      <strong>Advantages of Secondary Data</strong>\n      <ul>\n        <li>Already collected \u2014 saves time and cost</li>\n        <li>Covers large areas or long time periods</li>\n        <li>Often freely available</li>\n        <li>Allows comparison over decades</li>\n      </ul>\n    </div>\n    <div class=\"compare-col\">\n      <strong>Disadvantages of Secondary Data</strong>\n      <ul>\n        <li>May be outdated</li>\n        <li>May not match exact location or time needed</li>\n        <li>Reliability varies by source</li>\n        <li>Cannot control how it was collected</li>\n      </ul>\n    </div>\n  </div>\n  <div class=\"sg-spotlight\">Singapore's Department of Statistics (DOS) publishes annual census data, population trends, and economic statistics \u2014 a key secondary source for Singapore-based geographical investigations.</div>\n</div>\n\n<div class=\"notes-card\">\n  <h3>Section 4: Data Presentation Techniques</h3>\n  <table style=\"width:100%;border-collapse:collapse;\">\n    <tr style=\"background:#e8f4f8;\"><th style=\"padding:6px;border:1px solid #ccc;\">Technique</th><th style=\"padding:6px;border:1px solid #ccc;\">Best Used For</th><th style=\"padding:6px;border:1px solid #ccc;\">Advantages</th><th style=\"padding:6px;border:1px solid #ccc;\">Disadvantages</th></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Line Graph</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Change over time (trends); e.g., temperature over months</td><td style=\"padding:6px;border:1px solid #ccc;\">Clear trends visible; easy to compare multiple lines</td><td style=\"padding:6px;border:1px solid #ccc;\">Only for continuous data; misleading if scale poorly chosen</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Bar Graph (Compound/Grouped)</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Comparing categories; e.g., water use by sector</td><td style=\"padding:6px;border:1px solid #ccc;\">Easy to compare; clear visual; works for discrete data</td><td style=\"padding:6px;border:1px solid #ccc;\">Hard to show precise values; poor for change over time</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Pie Chart</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Proportions/percentages of a whole; e.g., land use distribution</td><td style=\"padding:6px;border:1px solid #ccc;\">Shows proportions clearly at a glance</td><td style=\"padding:6px;border:1px solid #ccc;\">Hard to compare two pie charts; fails with many small categories</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Scatter Graph</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Relationship/correlation between two variables</td><td style=\"padding:6px;border:1px solid #ccc;\">Shows correlation type (positive/negative/none); trend line possible</td><td style=\"padding:6px;border:1px solid #ccc;\">Does not prove causation; outliers can distort the trend</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Choropleth Map</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Spatial distribution using shading; e.g., population density by region</td><td style=\"padding:6px;border:1px solid #ccc;\">Immediate visual impression of spatial pattern</td><td style=\"padding:6px;border:1px solid #ccc;\">Data within each area assumed uniform; boundary issues</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Proportional Symbol Map</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Showing variation in values across locations on a map</td><td style=\"padding:6px;border:1px solid #ccc;\">Shows spatial variation clearly; easy to read relative sizes</td><td style=\"padding:6px;border:1px solid #ccc;\">Difficult to read precise values; symbols may overlap</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Annotated Field Sketch</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Recording complex spatial features from fieldwork</td><td style=\"padding:6px;border:1px solid #ccc;\">Captures spatial relationships; original; versatile</td><td style=\"padding:6px;border:1px solid #ccc;\">Subjective; cannot be computer-generated; skill-dependent</td></tr>\n  </table>\n  <div class=\"exam-tip\">In exams, you may be asked to choose the most appropriate presentation technique for a given dataset. Always justify your answer: e.g., \"A scatter graph is most appropriate because it shows the relationship between two continuous variables.\"</div>\n</div>\n\n<div class=\"notes-card\">\n  <h3>Section 5: Analysis, Conclusion and Evaluation</h3>\n  <div class=\"example\">\n    <strong>Writing a Description (Describe questions):</strong><br>\n    State the pattern \u2192 Give specific data example \u2192 Identify any anomalies<br>\n    <em>\"River velocity generally increases downstream, from 0.2 m/s at Site 1 to 1.1 m/s at Site 5. However, Site 3 shows an anomaly with a lower velocity of 0.4 m/s, possibly due to a wider channel.\"</em>\n  </div>\n  <div class=\"example\">\n    <strong>Writing an Explanation (Explain questions):</strong><br>\n    Link the observed pattern to geographical theory or cause<br>\n    <em>\"The increase in velocity downstream occurs because the channel becomes wider and deeper, reducing friction with the river bed and banks, so water flows faster.\"</em>\n  </div>\n  <div class=\"example\">\n    <strong>Drawing a Conclusion:</strong><br>\n    Directly answer the original question with evidence<br>\n    <em>\"The data supports the hypothesis that river velocity increases downstream. Evidence shows velocity rose from 0.2 m/s (Site 1) to 1.1 m/s (Site 5), consistent with the Bradshaw Model.\"</em>\n  </div>\n  <div class=\"stat-callout\">\n    <strong>Evaluating the Investigation \u2014 Key Criteria:</strong>\n    <ul>\n      <li><strong>Reliability:</strong> Were results consistent? Would repeat measurements give the same results?</li>\n      <li><strong>Validity:</strong> Did the method actually measure what it intended to?</li>\n      <li><strong>Limitations:</strong> Small sample size; time of day; weather conditions; human error</li>\n      <li><strong>Improvements:</strong> Larger sample; repeat measurements; additional locations; better equipment</li>\n    </ul>\n  </div>\n</div>\n\n<div class=\"notes-card\">\n  <h3>Section 6: Command Words and Mark Allocation</h3>\n  <table style=\"width:100%;border-collapse:collapse;\">\n    <tr style=\"background:#e8f4f8;\"><th style=\"padding:6px;border:1px solid #ccc;\">Command Word</th><th style=\"padding:6px;border:1px solid #ccc;\">What Examiners Want</th><th style=\"padding:6px;border:1px solid #ccc;\">Typical Marks</th></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>State / Name</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Give a fact without explanation</td><td style=\"padding:6px;border:1px solid #ccc;\">1\u20132</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Identify</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Pick out a key feature from a stimulus (graph/map/photo)</td><td style=\"padding:6px;border:1px solid #ccc;\">1\u20132</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Describe</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Say what you see \u2014 patterns, trends, specific values</td><td style=\"padding:6px;border:1px solid #ccc;\">2\u20134</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Explain</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Give reasons or causes \u2014 use \"because\", \"therefore\", \"this leads to\"</td><td style=\"padding:6px;border:1px solid #ccc;\">4\u20136</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Compare</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Show similarities AND differences; use \"whereas\", \"while\", \"in contrast\"</td><td style=\"padding:6px;border:1px solid #ccc;\">4\u20136</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Suggest</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Give a reasoned possibility \u2014 justify your suggestion</td><td style=\"padding:6px;border:1px solid #ccc;\">4\u20136</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Evaluate</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Weigh up strengths AND weaknesses; reach an overall conclusion</td><td style=\"padding:6px;border:1px solid #ccc;\">6\u20138</td></tr>\n    <tr><td style=\"padding:6px;border:1px solid #ccc;\"><strong>Discuss</strong></td><td style=\"padding:6px;border:1px solid #ccc;\">Consider multiple viewpoints; present a balanced argument</td><td style=\"padding:6px;border:1px solid #ccc;\">6\u20138</td></tr>\n  </table>\n  <div class=\"stat-callout\">\n    <strong>Key Exam Skills:</strong>\n    <ul>\n      <li>ALWAYS use geographical terms (e.g., \"discharge\", \"percolation\", \"sediment load\" \u2014 not just \"water flow\")</li>\n      <li>ALWAYS use data from graphs/maps in \"describe\" questions \u2014 quote specific values</li>\n      <li>ALWAYS answer in the context of the question scenario</li>\n      <li>For extended answers: use <strong>Point \u2192 Evidence \u2192 Explanation (PEE)</strong> structure</li>\n    </ul>\n  </div>\n  <div class=\"exam-tip\">For a 6-mark \"explain\" question: aim for 3 well-explained points. Each point needs: (1) the cause, (2) the process/mechanism, and (3) the outcome. Do not just list facts.</div>\n</div>";

